mapper.select:
SELECT Nuser_id, rdate, rtime, equipment_id, permit
FROM Restore_table
WHERE rdate = #{rdate}
  AND rtime = #{rtime}
  AND equipment_id = #{equipmentId}
  AND permit != '1'
LIMIT 1

SELECT Nuser_id, rdate, rtime, equipment_id, permit
FROM Restore_table
WHERE Nuser_id = #{nuserId}
  AND rdate = #{rdate}
  AND rtime = #{rtime}
  AND permit != '1'
LIMIT 1

mapper.update:
UPDATE Restore_table
SET permit = #{permit}
WHERE Nuser_id = #{nuserId}
  AND rdate = #{rdate}
  AND rtime = #{rtime}

mapper.delete:
DELETE FROM Restore_table
WHERE rdate < #{currentDate}
   OR (rdate = #{currentDate} AND #{expiredTime} != '-1' AND rtime <= #{expiredTime})

